from target import parse_duration

def test_parse_duration():
    # Simple mixed units
    assert parse_duration("1d2h3m4s") == 1*86400 + 2*3600 + 3*60 + 4
    # Zero values and single unit
    assert parse_duration("0h") == 0
    # Edge case: missing number before unit raises ValueError
    try:
        parse_duration("h")
        assert False, "Expected ValueError for missing number"
    except ValueError as e:
        assert str(e) == "missing number"
    # Edge case: trailing number without unit raises ValueError
    try:
        parse_duration("10")
        assert False, "Expected ValueError for trailing number without unit"
    except ValueError as e:
        assert str(e) == "trailing number without unit"
    # Edge case: empty string raises ValueError
    try:
        parse_duration("")
        assert False, "Expected ValueError for empty input"
    except ValueError as e:
        assert str(e) == "empty"
    # Invalid character raises ValueError
    try:
        parse_duration("5x")
        assert False, "Expected ValueError for bad character"
    except ValueError as e:
        assert str(e) == "bad character"
